# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {"case_id", 'tp', 'fp', 'fn', 'accuracy_only'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if record["accuracy_only"] is False else "REJECT_ACCURACY_ONLY"

valid = {"case_id": "CASO-LIM-034-1A", **{'tp': 1, 'fp': 1, 'fn': 0, 'accuracy_only': False}}
invalid = {"case_id": "CASO-LIM-034-1A", **{'tp': 0, 'fp': 0, 'fn': 0, 'accuracy_only': True}}
incomplete = {**valid}
incomplete.pop("tp")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
print(assess(valid))
missing = {k: valid[k] for k in valid if k != 'tp'}
print(assess(missing))

